import path from 'path';
export function normalizeRelativePath(str) {
    const normalized = path.posix.resolve('/', str).slice(1);
    // `path.posix.resolve` strips trailing slashes. Preserve one when the caller
    // provided it — OpenAPI path references like "openapi.json GET /users/" rely
    // on the trailing slash being part of the endpoint key to match the spec.
    if (str.endsWith('/') && normalized.length > 0 && !normalized.endsWith('/')) {
        return normalized + '/';
    }
    return normalized;
}
